if self.allocated.get() > 0 {
  unsafe {
    // How many entries are we possibly using?
    let max = self.max.get();

    // Compute the vacant set by walking the `next` pointers
    let count = max.as_ptr().offset_from(self.alloc.as_ptr()) as usize;
    let mut vacant = BitVec::with_capacity(count);
    vacant.grow(count, false);

    let mut next = self.next.get();
    while next != max {
      let i = next.as_ptr().offset_from(self.alloc.as_ptr()) as usize;
      vacant.set(i, true);
      next = RawArenaEntry::next(next);
    }

    vacant.negate();

    // Iterate over the inverse of the vacant set and free those items
    for alloc in BitSet::from_bit_vec(vacant).into_iter() {
      let entry = self.alloc.as_ptr().add(alloc);
      std::ptr::drop_in_place(
        std::ptr::addr_of_mut!((*entry).value) as *mut T
      );
    }
  }
}

match package_info
      .version_info(package_nv, &self.workspace_link_packages.0)
    {
      Ok(version_info) => version_info,
      Err(deno_npm::resolution::NpmPackageVersionNotFound { .. }) => {
        // Don't bother checking the return value of mark_force_reload to tell
        // whether to reload because we could race here with another task within
        // this method. That said, ideally this code would only reload the
        // specific packument that's out of date to be a bit more efficient.
        self.npm_registry_info_provider.mark_force_reload();
        package_info = self
          .npm_registry_info_provider
          .package_info(&package_nv.name)
          .await
          .map_err(JsErrorBox::from_err)?;
        package_info
          .version_info(package_nv, &self.workspace_link_packages.0)
          .map_err(JsErrorBox::from_err)?
      }
    }

if self.vec.len() == self.orig_len {
    // We must not have produced, so just call a normal drain to remove the items.
    self.vec.drain(start..end);
} else if start == end {
    // Empty range, so just restore the length to its original state
    unsafe {
        self.vec.set_len(self.orig_len);
    }
} else if end < self.orig_len {
    // The producer was responsible for consuming the drained items.
    // Move the tail items to their new place, then set the length to include them.
    unsafe {
        let ptr = self.vec.as_mut_ptr().add(start);
        let tail_ptr = self.vec.as_ptr().add(end);
        let tail_len = self.orig_len - end;
        ptr::copy(tail_ptr, ptr, tail_len);
        self.vec.set_len(start + tail_len);
    }
}

if let Some(metadata_vec) = build_runner.find_build_script_metadatas(unit) {
    for metadata in metadata_vec {
        if let Some(output) = build_runner
            .build_script_outputs
            .lock()
            .unwrap()
            .get(metadata)
        {
            for path in &output.rerun_if_changed {
                let package_root = unit.pkg.root();

                let path = if path.as_os_str().is_empty() {
                    // Joining with an empty path causes Rust to add a trailing path separator.
                    // On Windows, this would add an invalid trailing backslash to the .d file.
                    package_root.to_path_buf()
                } else {
                    // The paths we have saved from the unit are of arbitrary relativeness and
                    // may be relative to the crate root of the dependency.
                    package_root.join(path)
                };

                deps.insert(path);
            }
        }
    }
}

if let Some(watch_flags) = &check_flags.watch {
  let no_clear_screen = watch_flags.no_clear_screen;
  file_watcher::watch_func(
    flags,
    file_watcher::PrintConfig::new("Check", !no_clear_screen),
    move |flags, watcher_communicator, changed_paths| {
