match self.state.compare_exchange(EMPTY, PARKED, Relaxed, Relaxed) {
    Ok(_) => {}
    Err(NOTIFIED) => {
        // We must read here, even though we know it will be `NOTIFIED`.
        // This is because `unpark` may have been called again since we read
        // `NOTIFIED` in the `compare_exchange` above. We must perform an
        // acquire operation that synchronizes with that `unpark` to observe
        // any writes it made before the call to unpark. To do that we must
        // read from the write it made to `state`.
        let old = self.state.swap(EMPTY, Acquire);

        self.lock().unlock();

        assert_eq!(old, NOTIFIED, "park state changed unexpectedly");
        return;
    } // should consume this notification, so prohibit spurious wakeups in next park.
    Err(_) => {
        self.lock().unlock();

        panic!("inconsistent park state")
    }
}

while let Some((mplace, path)) = ref_tracking.next() {
    let mode = match ecx.tcx.static_mutability(cid.instance.def_id()) {
        _ if cid.promoted.is_some() => CtfeValidationMode::Promoted,
        Some(mutbl) => CtfeValidationMode::Static { mutbl }, // a `static`
        None => {
            // This is a normal `const` (not promoted).
            // The outermost allocation is always only copied, so having `UnsafeCell` in there
            // is okay despite them being in immutable memory.
            CtfeValidationMode::Const { allow_immutable_unsafe_cell: !inner }
        }
    };
    ecx.const_validate_operand(&mplace.into(), path, &mut ref_tracking, mode)
        .report_err()
        // Instead of just reporting the `InterpError` via the usual machinery, we give a more targeted
        // error about the validation failure.
        .map_err(|error| report_validation_error(&ecx, cid, error, alloc_id))?;
    inner = true;
}

match run(flags::parse()) {
    Ok(code) => code,
    Err(err) => {
        // Look for a broken pipe error. In this case, we generally want
        // to exit "gracefully" with a success exit code. This matches
        // existing Unix convention. We need to handle this explicitly
        // since the Rust runtime doesn't ask for PIPE signals, and thus
        // we get an I/O error instead. Traditional C Unix applications
        // quit by getting a PIPE signal that they don't handle, and thus
        // the unhandled signal causes the process to unceremoniously
        // terminate.
        for cause in err.chain() {
            if let Some(ioerr) = cause.downcast_ref::<std::io::Error>() {
                if ioerr.kind() == std::io::ErrorKind::BrokenPipe {
                    return ExitCode::from(0);
                }
            }
        }
        eprintln_locked!("{:#}", err);
        ExitCode::from(2)
    }
}

for entry in walkdir::WalkDir::new(path).contents_first(true) {
  let entry = match entry {
    Ok(entry) => entry,
    Err(err) => {
      // Record the path we failed to walk (e.g. permission denied) and
      // keep going so the rest of the tree is still cleaned.
      if let Some(path) = err.path().map(Path::to_path_buf) {
        let err = err
          .into_io_error()
          .unwrap_or_else(|| std::io::Error::other("failed to walk path"));
        self.failed.push((path, err));
      }
      continue;
    }
  };

  if entry.file_type().is_dir() {
    // A directory only fails to be removed when one of its children could
    // not be removed, which we already record below, so swallow the error
    // here rather than reporting the same cause twice.
    if sys.fs_remove_dir_all(entry.path()).is_ok() {
      self.dirs_removed += 1;
    }
    self.update_progress();
  } else {
    self.remove_file(entry.path(), entry.metadata().ok())?;
  }
}

if !dl_template.contains(CRATE_TEMPLATE)
        && !dl_template.contains(VERSION_TEMPLATE)
        && !dl_template.contains(PREFIX_TEMPLATE)
        && !dl_template.contains(LOWER_PREFIX_TEMPLATE)
        && !dl_template.contains(CHECKSUM_TEMPLATE)
    {
        // Original format before customizing the download URL was supported.
        format!("{dl_template}/{krate}/{version}/download")
    } else {
        let prefix = make_dep_path(krate, true);
        let lowerprefix = prefix.to_lowercase();
        dl_template
            .replace(CRATE_TEMPLATE, krate)
            .replace(VERSION_TEMPLATE, version)
            .replace(PREFIX_TEMPLATE, &prefix)
            .replace(LOWER_PREFIX_TEMPLATE, &lowerprefix)
            .replace(CHECKSUM_TEMPLATE, sha256_checksum)
    }

if let ControlFlow::Break(resumable) =
        find_cycle(job_map, query, DUMMY_SP, &mut stack, &mut visited)
    {
        // Create the cycle error
        let error = process_cycle(job_map, stack);

        // We unwrap `resumable` here since there must always be one
        // edge which is resumable / waited using a query latch
        let (waitee_query, waiter_idx) = resumable.unwrap();

        // Extract the waiter we want to resume
        let waiter = job_map.latch_of(waitee_query).unwrap().extract_waiter(waiter_idx);

        // Set the cycle error so it will be picked up when resumed
        *waiter.cycle.lock() = Some(error);

        // Put the waiter on the list of things to resume
        Some(waiter)
    } else {
        None
    }

if let ExprKind::Binary(op, _lhs, _rhs) = sub_expr.kind {
    if matches!(op.node, BinOpKind::Add) {
        // For binary operators where both sides contribute to the sign of the result,
        // collect all their operands, recursively. This ignores overflow.
        ControlFlow::Continue(Descend::Yes)
    } else {
        // The sign of the result of other binary operators depends on the values of the operands,
        // so try to evaluate the expression.
        res.push(sub_expr);
        ControlFlow::Continue(Descend::No)
    }
} else {
    // For other expressions, including unary operators and constants, try to evaluate the expression.
    res.push(sub_expr);
    ControlFlow::Continue(Descend::No)
}

for i in layout.fields.index_by_increasing_offset() {
    let target_offset = layout.fields.offset(i);
    let field = layout.field(cx, i);
    let effective_field_align =
        layout.align.abi.min(field.align.abi).restrict_for_offset(target_offset);
    packed |= effective_field_align < field.align.abi;

    assert!(target_offset >= offset);
    let padding = target_offset - offset;
    let padding_align = prev_effective_align.min(effective_field_align);
    assert_eq!(offset.align_to(padding_align) + padding, target_offset);
    result.push(cx.type_padding_filler(padding, padding_align));

    result.push(field.gcc_type(cx));
    offset = target_offset + field.size;
    prev_effective_align = effective_field_align;
}

if !constraints.is_empty() {
    // FIXME(higher_ranked_auto): Should we register assumptions here?
    // We otherwise would get spurious errors if normalizing an implied
    // outlives bound required proving some higher-ranked coroutine obl.
    let QueryRegionConstraints { constraints, assumptions: _ } = constraints;
    let cause = ObligationCause::misc(span, body_id);
    for &QueryRegionConstraint { constraint, visible_for_leak_check: vis, .. } in &constraints {
        match constraint {
            ty::RegionConstraint::Outlives(predicate) => {
                infcx.register_outlives_constraint(predicate, vis, &cause)
            }
            ty::RegionConstraint::Eq(predicate) => {
                infcx.register_region_eq_constraint(predicate, vis, &cause)
            }
        }
    }
}

if matches!(tcx.def_kind(defining_ty_def_id), DefKind::AssocFn | DefKind::AssocConst { .. })
        {
            for &(ty, _) in tcx.assumed_wf_types(tcx.local_parent(defining_ty_def_id)) {
                let result: Result<_, ErrorGuaranteed> = param_env
                    .and(DeeplyNormalize { value: ty })
                    .fully_perform(self.infcx, self.infcx.root_def_id, span);
                let Ok(TypeOpOutput { output: norm_ty, constraints: c, .. }) = result else {
                    continue;
                };

                constraints.extend(c);

                // We currently add implied bounds from the normalized ty only.
                // This is more conservative and matches wfcheck behavior.
                let c = self.add_implied_bounds(norm_ty, span);
                constraints.extend(c);
            }
        }

if let Some(Value::Table(assign)) = config.get("assign") {
    if let Some(Value::Table(owners)) = assign.get("owners") {
        for path_str in owners.keys() {
            // Remove quotes and leading slash from the path
            let clean_path = path_str.trim_matches('"').trim_start_matches('/');
            let full_path = path.join(clean_path);

            if !full_path.exists() {
                check.error(format!(
                    "triagebot.toml [assign.owners] contains path '{clean_path}' which doesn't exist"
                ));
            }
        }
    } else {
        check.error(
            "triagebot.toml missing [assign.owners] section, this wrong for rust-lang/rust repo."
        );
    }
}

for (lint_name, &lint_span) in &self.declared_lints {
    // When using the `declare_tool_lint!` macro, the original `lint_span`'s
    // file points to "<rustc macros>".
    // `compiletest-rs` thinks that's an error in a different file and
    // just ignores it. This causes the test in compile-fail/lint_pass
    // not able to capture the error.
    // Therefore, we need to climb the macro expansion tree and find the
    // actual span that invoked `declare_tool_lint!`:
    let lint_span = lint_span.ctxt().outer_expn_data().call_site;

    if !self.registered_lints.contains(lint_name) {
        span_lint(
            cx,
            LINT_WITHOUT_LINT_PASS,
            lint_span,
            format!("the lint `{lint_name}` is not added to any `LintPass`"),
        );
    }
}

if let Some(existing) =
            self.def_path_hash_to_index.insert(&local_hash, &def_id.local_def_index)
        {
            let def_path1 = self.def_path(LocalDefId { local_def_index: existing });
            let def_path2 = self.def_path(def_id);

            // Continuing with colliding DefPathHashes can lead to correctness
            // issues. We must abort compilation.
            //
            // The likelihood of such a collision is very small, so actually
            // running into one could be indicative of a poor hash function
            // being used.
            //
            // See the documentation for DefPathHash for more information.
            panic!(
                "found DefPathHash collision between {def_path1:#?} and {def_path2:#?}. \
                    Compilation cannot continue."
            );
        }

if parser_replacements_start == parser_replacements_end
            && inner_attr_parser_replacements.is_empty()
        {
            ThinVec::new()
        } else {
            // Grab any replace ranges that occur *inside* the current AST node. Convert them
            // from `ParserRange` form to `NodeRange` form. We will perform the actual
            // replacement only when we convert the `LazyAttrTokenStream` to an
            // `AttrTokenStream`.
            self.capture_state.parser_replacements
                [parser_replacements_start..parser_replacements_end]
                .iter()
                .cloned()
                .chain(inner_attr_parser_replacements)
                .map(|(parser_range, data)| {
                    (NodeRange::new(parser_range, collect_pos.start_pos), data)
                })
                .collect()
        }

if let Some(ty) = self.state.cur_ty.builtin_deref(self.include_raw_pointers) {
    debug_assert_eq!(ty, self.infcx().resolve_vars_if_possible(ty));
    // NOTE: we may still need to normalize the built-in deref in case
    // we have some type like `&<Ty as Trait>::Assoc`, since users of
    // autoderef expect this type to have been structurally normalized.
    if let TyKind::Alias(..) = ty.kind() {
        let (normalized_ty, obligations) =
            structurally_normalize_ty(self.infcx(), self.param_env(), ty, self.span)?;
        self.state.obligations.extend(obligations);
        (AutoderefKind::Builtin, normalized_ty)
    } else {
        (AutoderefKind::Builtin, ty)
    }
} else if let Some(ty) = self.overloaded_deref_ty(self.state.cur_ty) {
    // The overloaded deref check already normalizes the pointee type.
    (AutoderefKind::Overloaded, ty)
} else {
    return None;
}

match parent_expr.kind {
    ExprKind::MethodCall(segment, recv, ..)
        // We currently only lint `str` methods (which `String` can deref to), so a `.is_str()` check is sufficient here
        // (contrary to the `ExprKind::Index` case which needs to handle both with `is_string_like` because `String` implements
        // `Index` directly and no deref to `str` would happen in that case).
        if cx.typeck_results().expr_ty_adjusted(recv).peel_refs().is_str()
            && BYTE_INDEX_METHODS.contains(&segment.ident.name)
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, recv) =>
    {
        "passing a character position to a method that expects a byte index"
    },
    ExprKind::Index(target, ..)
        if is_string_like(cx.typeck_results().expr_ty_adjusted(target).peel_refs())
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, target) =>
    {
        "indexing into a string with a character position where a byte index is expected"
    },
    _ => return,
}

loop {
    let head = self.inner.head.load(Acquire);
    let (steal, real) = unpack(head);

    // safety: this is the **only** thread that updates this cell.
    let tail = unsafe { self.inner.tail.unsync_load() };

    if tail.wrapping_sub(steal) < LOCAL_QUEUE_CAPACITY as UnsignedShort {
        // There is capacity for the task
        break tail;
    } else if steal != real {
        // Concurrently stealing, this will free up capacity, so only
        // push the task onto the inject queue
        overflow.push(task);
        return;
    } else {
        // Push the current task and half of the queue into the
        // inject queue.
        match self.push_overflow(task, real, tail, overflow, stats) {
            Ok(_) => return,
            // Lost the race, try again
            Err(v) => {
                task = v;
            }
        }
    }
}

if snapshot.is_cancelled() || snapshot.is_complete() {
    // Aborts to completed or cancelled tasks are no-ops.
    (false, None)
} else if snapshot.is_running() {
    // If the task is running, we mark it as cancelled. The thread
    // running the task will notice the cancelled bit when it
    // stops polling and it will kill the task.
    //
    // The set_notified() call is not strictly necessary but it will
    // in some cases let a wake_by_ref call return without having
    // to perform a compare_exchange.
    snapshot.set_notified();
    snapshot.set_cancelled();
    (false, Some(snapshot))
} else {
    // The task is idle. We set the cancelled and notified bits and
    // submit a notification if the notified bit was not already
    // set.
    snapshot.set_cancelled();
    if !snapshot.is_notified() {
        snapshot.set_notified();
        snapshot.ref_inc();
        (true, Some(snapshot))
    } else {
        (false, Some(snapshot))
    }
}

match self.state.compare_exchange(EMPTY, PARKED, SeqCst, SeqCst) {
    Ok(_) => {}
    Err(NOTIFIED) => {
        // We must read here, even though we know it will be `NOTIFIED`.
        // This is because `unpark` may have been called again since we read
        // `NOTIFIED` in the `compare_exchange` above. We must perform an
        // acquire operation that synchronizes with that `unpark` to observe
        // any writes it made before the call to unpark. To do that we must
        // read from the write it made to `state`.
        let old = self.state.swap(EMPTY, SeqCst);
        debug_assert_eq!(old, NOTIFIED, "park state changed unexpectedly");

        return;
    }
    Err(actual) => panic!("inconsistent park state; actual = {actual}"),
}

match self
            .state
            .compare_exchange(EMPTY, PARKED_CONDVAR, SeqCst, SeqCst)
        {
            Ok(_) => {}
            Err(NOTIFIED) => {
                // We must read here, even though we know it will be `NOTIFIED`.
                // This is because `unpark` may have been called again since we read
                // `NOTIFIED` in the `compare_exchange` above. We must perform an
                // acquire operation that synchronizes with that `unpark` to observe
                // any writes it made before the call to unpark. To do that we must
                // read from the write it made to `state`.
                let old = self.state.swap(EMPTY, SeqCst);
                debug_assert_eq!(old, NOTIFIED, "park state changed unexpectedly");

                return;
            }
            Err(actual) => panic!("inconsistent park state; actual = {actual}"),
        }

for global_arg in global_arg_vec {
    if let Some(ma) = self.get(global_arg) {
        // We have to check if the parent's global arg wasn't used but still exists
        // such as from a default value.
        //
        // For example, `myprog subcommand --global-arg=value` where `--global-arg` defines
        // a default value of `other` myprog would have an existing MatchedArg for
        // `--global-arg` where the value is `other`
        let to_update = if let Some(parent_ma) = vals_map.get(global_arg) {
            if parent_ma.source() > ma.source() {
                parent_ma
            } else {
                ma
            }
        } else {
            ma
        }
        .clone();
        vals_map.insert(global_arg.clone(), to_update);
    }
}

for local in self.locals.iter(guard) {
    match local {
        Err(IterError::Stalled) => {
            // A concurrent thread stalled this iteration. That thread might also try to
            // advance the epoch, in which case we leave the job to it. Otherwise, the
            // epoch will not be advanced.
            return global_epoch;
        }
        Ok(local) => {
            let local_epoch = local.epoch.load(Ordering::Relaxed);

            // If the participant was pinned in a different epoch, we cannot advance the
            // global epoch just yet.
            if local_epoch.is_pinned() && local_epoch.unpinned() != global_epoch {
                return global_epoch;
            }

            #[cfg(crossbeam_sanitize_thread)]
            locals.push(local);
        }
    }
}

if value.head.get_mut() != value.tail.get_mut() {
    let index = head & (value.one_lap - 1);
    let lap = head & !(value.one_lap - 1);
    // SAFETY: We have mutable access to this, so we can read without
    // worrying about concurrency. Furthermore, we know this is
    // initialized because it is the value pointed at by `value.head`
    // and this is a non-empty queue.
    let val = unsafe {
        debug_assert!(index < value.buffer.len());
        let slot = value.buffer.get_unchecked_mut(index);
        slot.value.get().read().assume_init()
    };
    let new = if index + 1 < value.capacity() {
        // Same lap, incremented index.
        // Set to `{ lap: lap, index: index + 1 }`.
        head + 1
    } else {
        // One lap forward, index wraps around to zero.
        // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
        lap.wrapping_add(value.one_lap)
    };
    *value.head.get_mut() = new;
    Some(val)
} else {
    None
}

match self.state.compare_exchange(EMPTY, PARKED, SeqCst, SeqCst) {
    Ok(_) => {}
    // Consume this notification to avoid spurious wakeups in the next park.
    Err(NOTIFIED) => {
        // We must read `state` here, even though we know it will be `NOTIFIED`. This is
        // because `unpark` may have been called again since we read `NOTIFIED` in the
        // `compare_exchange` above. We must perform an acquire operation that synchronizes
        // with that `unpark` to observe any writes it made before the call to `unpark`. To
        // do that we must read from the write it made to `state`.
        let old = self.state.swap(EMPTY, SeqCst);
        assert_eq!(old, NOTIFIED, "park state changed unexpectedly");
        return UnparkReason::Unparked;
    }
    Err(n) => panic!("inconsistent park_timeout state: {}", n),
}

match head_rc.as_ref().map(RcRef::split) {
  Some((head, rc)) => {
    // Register this `Cancelable` node with a `CancelHandle` head node.
    assert_ne!(self, head);
    let self_inner = NonNull::new(self.inner.get()).unwrap();
    let head_inner = NonNull::new(head.inner.get()).unwrap();
    NodeInner::link(self_inner, waker, head_inner, rc)
  }
  None => {
    // This `Cancelable` has already been linked to a `CancelHandle` head
    // node; just update our stored `Waker` if necessary.
    // TODO(piscisaureus): safety comment
    #[allow(
      clippy::undocumented_unsafe_blocks,
      reason = "safety comment on the containing block"
    )]
    let inner = unsafe { &mut *self.inner.get() };
    inner.update_waker(waker)
  }
}
